import { GoogleLogin } from "@react-oauth/google";
import { jwtDecode } from "jwt-decode";
import React, { useState, useContext } from "react";
import { Link, useNavigate } from "react-router-dom";
import { AuthContext } from "../context/AuthContext";

const Login = () => {
  const [mode, setMode] = useState("login"); // "login" hoặc "register"
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [subscribeNewsletter, setSubscribeNewsletter] = useState(true);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const { login, register } = useContext(AuthContext);

  // 🔹 Login thường
  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    if (!email || !password) return setError("Vui lòng nhập đầy đủ thông tin");

    try {
      const result = await login(email, password);
      if (result?.success) {
        if (result.user.role === "admin") navigate("/admin");
        else navigate("/");
      } else {
        setError(result?.message || "Sai thông tin đăng nhập!");
      }
    } catch {
      setError("Lỗi đăng nhập!");
    }
    setLoading(false);
  };

  // 🔹 Register thường
  const handleRegister = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    if (!name || !email || !password)
      return setError("Vui lòng nhập đầy đủ họ tên, email và mật khẩu");

    try {
      const result = await register(name, email, password, "", "", subscribeNewsletter);
      if (result?.success) navigate("/");
      else setError(result?.message || "Đăng ký thất bại. Vui lòng thử lại.");
    } catch {
      setError("Có lỗi xảy ra khi đăng ký. Vui lòng thử lại.");
    }
    setLoading(false);
  };

  // 🔹 Google Login (dùng cho cả đăng ký và đăng nhập)
  
  
  const handleGoogleLogin = async (credentialResponse) => {
    try {
      const decoded = jwtDecode(credentialResponse.credential);
      const response = await fetch("http://localhost:5000/api/auth/google", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: decoded.email,
          name: decoded.name,
          googleId: decoded.sub,
          picture: decoded.picture,
        }),
      });
      const data = await response.json();
      if (data.success) {
        localStorage.setItem("user", JSON.stringify(data.user));
        localStorage.setItem("token", data.token);

        if (data.user.role === "admin") {
          navigate("/admin");
        } else {
          navigate("/");
        }
      } else {
        setError("Không thể đăng nhập bằng Google.");
      }
    } catch (error) {
      console.error(error);
      setError("Lỗi máy chủ, vui lòng thử lại sau.");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#faf8f6] px-4 py-10">
      <div className="w-full max-w-md bg-white shadow-lg rounded-2xl border border-[#f2e4e0] p-8">
        <h2 className="text-center text-2xl font-semibold text-[#e06c7f] mb-6">
          {mode === "login" ? "🌸 Đăng nhập tài khoản" : "🌷 Tạo tài khoản mới"}
        </h2>

        {error && (
          <div className="bg-red-100 text-red-700 p-3 rounded-lg mb-4 text-center">
            ⚠️ {error}
          </div>
        )}

        {mode === "login" ? (
          <>
            {/* FORM ĐĂNG NHẬP */}
            <form onSubmit={handleLogin}>
              <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
              />
              <div className="relative mb-6">
                <input
                  type={showPassword ? "text" : "password"}
                  placeholder="Mật khẩu"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full p-3 pr-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-3 text-gray-500 hover:text-[#e06c7f]"
                >
                  {showPassword ? "🙈" : "👁️"}
                </button>
              </div>

              <button
                type="submit"
                className="w-full bg-[#e06c7f] text-white py-3 rounded-lg font-medium hover:bg-[#d35c70] transition"
              >
                {loading ? "Đang đăng nhập..." : "Đăng nhập"}
              </button>

              {/* --- hoặc đăng nhập bằng Google --- */}
              <div className="flex items-center my-4">
                <div className="flex-grow h-px bg-gray-300"></div>
                <span className="px-3 text-gray-500 text-sm">hoặc</span>
                <div className="flex-grow h-px bg-gray-300"></div>
              </div>

              <div className="flex justify-center">
                <GoogleLogin
                  onSuccess={handleGoogleLogin}
                  onError={() => setError("Đăng nhập Google thất bại!")}
                />
              </div>

              <div className="text-center mt-4 text-sm">
                <Link
                  to="#"
                  onClick={() => setMode("register")}
                  className="text-[#e06c7f] hover:underline"
                >
                  ✨ Chưa có tài khoản? Đăng ký ngay
                </Link>
              </div>
            </form>
          </>
        ) : (
          <>
            {/* FORM ĐĂNG KÝ */}
            <form onSubmit={handleRegister}>
              <input
                type="text"
                placeholder="Họ tên"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
              />
              <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
              />
              <input
                type="password"
                placeholder="Mật khẩu"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full mb-3 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
              />

              <label className="flex items-center mb-5 text-sm text-gray-700">
                <input
                  type="checkbox"
                  checked={subscribeNewsletter}
                  onChange={(e) => setSubscribeNewsletter(e.target.checked)}
                  className="mr-2 accent-[#e06c7f]"
                />
                📧 Nhận tin khuyến mãi & ưu đãi
              </label>

              <button
                type="submit"
                className="w-full bg-[#e06c7f] text-white py-3 rounded-lg font-medium hover:bg-[#d35c70] transition"
              >
                {loading ? "Đang đăng ký..." : "Đăng ký tài khoản"}
              </button>

              {/* --- hoặc đăng ký bằng Google --- */}
              <div className="flex items-center my-4">
                <div className="flex-grow h-px bg-gray-300"></div>
                <span className="px-3 text-gray-500 text-sm">hoặc</span>
                <div className="flex-grow h-px bg-gray-300"></div>
              </div>

              <div className="flex justify-center">
                <GoogleLogin
                  onSuccess={handleGoogleLogin}
                  onError={() => setError("Đăng ký Google thất bại!")}
                />
              </div>

              <div className="text-center mt-4 text-sm">
                <Link
                  to="#"
                  onClick={() => setMode("login")}
                  className="text-[#e06c7f] hover:underline"
                >
                  🔙 Đã có tài khoản? Quay lại đăng nhập
                </Link>
              </div>
            </form>
          </>
        )}
      </div>
    </div>
  );
};

export default Login;
